Bash(cd /d/laragon/www/dietwatcher/website && php artisan tinker --execute="
\\$s = app\(App\\Services\\ExternalDataService::class\);
\\$programs = \\$s->getPrograms\(\);
echo 'Programs: ' . count\(\\$programs\) . PHP_EOL;
if \(count\(\\$programs\) > 0\) {
    \\$first = \\$programs[0];
    echo 'First program:' . PHP_EOL;
    echo '  id: ' . \\$first['id'] . PHP_EOL;
    echo '  name: ' . \\$first['name'] . PHP_EOL;
    echo '  price: ' . \\$first['price'] . PHP_EOL;
    echo '  image_url: ' . \\$first['image_url'] . PHP_EOL;
    echo '  calories_per_day: ' . \\$first['calories_per_day'] . PHP_EOL;
    echo '  duration_days: ' . \\$first['duration_days'] . PHP_EOL;
}
" 2>&1)

